package main

import (
    "crypto/tls"
    "crypto/x509"
    "errors"
    "io/ioutil"
    "net/http"
    "time"
)

// Compliant: Using default secure HTTP client
func makeSecureRequest(url string) (*http.Response, error) {
    // Default client has certificate verification enabled
    client := &http.Client{
        Timeout: 30 * time.Second,
    }

    return client.Get(url)
}

// Compliant: Secure TLS configuration
func makeRequestWithSecureTLS(url string) (*http.Response, error) {
    tr := &http.Transport{
        TLSClientConfig: &tls.Config{
            MinVersion: tls.VersionTLS12, // Minimum secure version
            CipherSuites: []uint16{
                tls.TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384,
                tls.TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384,
                tls.TLS_ECDHE_RSA_WITH_CHACHA20_POLY1305,
                tls.TLS_ECDHE_ECDSA_WITH_CHACHA20_POLY1305,
            },
            PreferServerCipherSuites: true,
            // Certificate verification is enabled by default
        },
        TLSHandshakeTimeout: 10 * time.Second,
    }

    client := &http.Client{
        Transport: tr,
        Timeout:   30 * time.Second,
    }

    return client.Get(url)
}

// Compliant: Custom certificate verification with proper checks
func makeRequestWithCustomCA(url string, caCertPath string) (*http.Response, error) {
    // Load custom CA certificate
    caCert, err := ioutil.ReadFile(caCertPath)
    if err != nil {
        return nil, err
    }

    caCertPool := x509.NewCertPool()
    if !caCertPool.AppendCertsFromPEM(caCert) {
        return nil, errors.New("failed to parse CA certificate")
    }

    tr := &http.Transport{
        TLSClientConfig: &tls.Config{
            RootCAs:    caCertPool,
            MinVersion: tls.VersionTLS12,
            // Certificate verification includes CA validation
        },
    }

    client := &http.Client{Transport: tr}
    return client.Get(url)
}

// Compliant: Certificate pinning for high-security scenarios
func makeRequestWithCertPinning(url string, expectedCertHash []byte) (*http.Response, error) {
    tr := &http.Transport{
        TLSClientConfig: &tls.Config{
            MinVersion: tls.VersionTLS12,
            VerifyPeerCertificate: func(rawCerts [][]byte, verifiedChains [][]*x509.Certificate) error {
                // First, perform standard verification
                if len(verifiedChains) == 0 {
                    return errors.New("no verified certificate chains")
                }

                // Then check certificate pinning
                cert := verifiedChains[0][0]
                certHash := sha256.Sum256(cert.Raw)

                if !bytes.Equal(certHash[:], expectedCertHash) {
                    return errors.New("certificate does not match pinned hash")
                }

                return nil
            },
        },
    }

    client := &http.Client{Transport: tr}
    return client.Get(url)
}

// Compliant: Secure TLS connection with full validation
func connectSecurely(hostname string, port string) (*tls.Conn, error) {
    config := &tls.Config{
        ServerName: hostname,
        MinVersion: tls.VersionTLS12,
        // Full certificate validation is performed
    }

    address := hostname + ":" + port
    return tls.Dial("tcp", address, config)
}

// Compliant: Secure client factory with validation
func createSecureClient(timeout time.Duration) *http.Client {
    return &http.Client{
        Timeout: timeout,
        Transport: &http.Transport{
            TLSClientConfig: &tls.Config{
                MinVersion:               tls.VersionTLS12,
                PreferServerCipherSuites: true,
                CurvePreferences: []tls.CurveID{
                    tls.X25519,
                    tls.CurveP256,
                    tls.CurveP384,
                },
                // Default secure settings for certificate validation
            },
            TLSHandshakeTimeout: 10 * time.Second,
            IdleConnTimeout:     90 * time.Second,
        },
    }
}

// Compliant: Certificate validation utility
func validateCertificate(cert *x509.Certificate, hostname string) error {
    // Verify certificate is valid for hostname
    if err := cert.VerifyHostname(hostname); err != nil {
        return err
    }

    // Check certificate validity period
    now := time.Now()
    if now.Before(cert.NotBefore) || now.After(cert.NotAfter) {
        return errors.New("certificate is not valid for current time")
    }

    return nil
}

// Compliant: Error handling that doesn't bypass security
func makeRequestWithProperErrorHandling(url string) (*http.Response, error) {
    resp, err := http.Get(url)
    if err != nil {
        // Log the error but don't retry without verification
        return nil, fmt.Errorf("secure request failed: %w", err)
    }
    return resp, nil
}
